/**
 * Sanctions screening block — onboarding gate.
 *
 * Blocks onboarding for any entity whose compliance screening
 * contains a sanctions match with match_score >= 0.80 (80%)
 * that has not been cleared as a false positive.
 *
 * This prevents sanctioned parties from being onboarded onto
 * the platform. A compliance analyst can clear the match via
 * manual_override to allow onboarding to proceed.
 *
 * Regulatory basis: OFAC compliance (31 CFR §501),
 * UN Security Council Resolutions, country-specific sanctions.
 */
export const handler = async (input) => {
  const MATCH_THRESHOLD = 0.80;
  const CLEARED = ['manual_override', 'auto_suppressed'];

  const screenings = input.compliance_screenings || [];

  const hasHighScoreMatch = screenings.some(function (s) {
    if (CLEARED.indexOf(s.false_positive_qualifier) >= 0) return false;
    const matches = s.sanctions_matches || [];
    return matches.some(function (m) {
      return typeof m.match_score === 'number' && m.match_score >= MATCH_THRESHOLD;
    });
  });

  if (!hasHighScoreMatch) return { ledger_accounts: {} };

  const las = input.las || [];
  const ledger_accounts = {};
  for (const la of las) {
    ledger_accounts[la.id] = {
      daily_debit_cap: 0,
      daily_credit_cap: 0,
      reason: 'sanctions_screening_block',
      block_reason: 'sanctions_screening_block',
      is_blocked: true
    };
  }
  return { ledger_accounts };
};
